from functools import lru_cache

class Solution:
    def countWinningHands(self, colors, numbers):
        # 统计 27 种牌的数量
        counts = [0] * 27
        for c, n in zip(colors, numbers):
            idx = (c - 1) * 9 + (n - 1)
            counts[idx] += 1

        @lru_cache(None)
        def dfs(state):
            # state 是不可变元组，方便作为记忆化搜索的键
            arr = list(state)

            # 找到当前还剩的最小下标牌
            first = -1
            for i in range(27):
                if arr[i] > 0:
                    first = i
                    break

            # 没有剩余牌，说明全部成功拆成面子
            if first == -1:
                return 1

            ans = 0

            # 尝试拆刻子：三张完全相同的牌
            if arr[first] >= 3:
                arr[first] -= 3
                ans += dfs(tuple(arr))
                arr[first] += 3

            # 尝试拆顺子：同花色连续三张
            suit = first // 9
            rank = first % 9

            # rank <= 6 表示点数不超过 7，才可能组成 x, x+1, x+2
            if rank <= 6:
                second = first + 1
                third = first + 2

                # second 和 third 一定还在同一花色内
                if arr[second] > 0 and arr[third] > 0:
                    arr[first] -= 1
                    arr[second] -= 1
                    arr[third] -= 1

                    ans += dfs(tuple(arr))

                    arr[first] += 1
                    arr[second] += 1
                    arr[third] += 1

            return ans

        total = 0

        # 枚举将牌
        for i in range(27):
            if counts[i] >= 2:
                counts[i] -= 2
                total += dfs(tuple(counts))
                counts[i] += 2

        return total
