import java.util.*;

class Solution {
    private HashMap<String, Long> memo;

    public long countWinningHands(int[] colors, int[] numbers) {
        int[] counts = new int[27];

        // 统计 27 种牌的数量
        for (int i = 0; i < 14; i++) {
            int idx = (colors[i] - 1) * 9 + (numbers[i] - 1);
            counts[idx]++;
        }

        memo = new HashMap<>();
        long total = 0;

        // 枚举将牌
        for (int i = 0; i < 27; i++) {
            if (counts[i] >= 2) {
                counts[i] -= 2;
                total += dfs(counts);
                counts[i] += 2;
            }
        }

        return total;
    }

    private long dfs(int[] counts) {
        String key = encode(counts);
        if (memo.containsKey(key)) {
            return memo.get(key);
        }

        // 找到当前还剩的最小下标牌
        int first = -1;
        for (int i = 0; i < 27; i++) {
            if (counts[i] > 0) {
                first = i;
                break;
            }
        }

        // 没有剩余牌，说明全部成功拆成面子
        if (first == -1) {
            return 1;
        }

        long ans = 0;

        // 尝试拆刻子：三张完全相同的牌
        if (counts[first] >= 3) {
            counts[first] -= 3;
            ans += dfs(counts);
            counts[first] += 3;
        }

        // 尝试拆顺子：同花色连续三张
        int rank = first % 9;

        // rank <= 6 表示点数不超过 7，才可能组成 x, x+1, x+2
        if (rank <= 6) {
            int second = first + 1;
            int third = first + 2;

            if (counts[second] > 0 && counts[third] > 0) {
                counts[first]--;
                counts[second]--;
                counts[third]--;

                ans += dfs(counts);

                counts[first]++;
                counts[second]++;
                counts[third]++;
            }
        }

        memo.put(key, ans);
        return ans;
    }

    private String encode(int[] counts) {
        StringBuilder sb = new StringBuilder();

        // 每种牌数量不会很多，用分隔符拼接即可唯一表示状态
        for (int x : counts) {
            sb.append(x).append('#');
        }

        return sb.toString();
    }
}
